SELECT pt.id, pt.name, pt.description, pt.category_id, pt.content, pt.variables, pt.is_builtin, pt.status, pt.created_by, pt.created_at, pt.updated_at, pt.is_deleted, pc.name as category_name FROM prompt_template pt LEFT JOIN prompt_category pc ON pt.category_id = pc.id WHERE pt.is_deleted = 0
AND pt.category_id = #{categoryId}
AND (pt.name LIKE CONCAT('%', #{keyword}, '%') OR pt.description LIKE CONCAT('%', #{keyword}, '%'))
AND pt.status = #{status}
ORDER BY pt.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM prompt_template WHERE is_deleted = 0
AND category_id = #{categoryId}
AND (name LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
